INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("", 34, 14, 8, 0, 91002, 100, "", 0, 30000, 0);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("", 35, 15, 2, 0, 24001, 1, "", 0, 30000, 0);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("", 36, 1, 8, 0, 91002, 100, "", 0, 40000, 0);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("ぺコリーヌ", 37, 1, 8, 0, 91002, 150, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 107501, 40001, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("コッコロ", 38, 2, 8, 0, 91002, 150, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 107601, 40001, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("キャル", 39, 3, 8, 0, 91002, 150, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 107801, 40001, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("スズメ", 40, 4, 8, 0, 91002, 150, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 107701, 40001, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("タマキ", 41, 5, 8, 0, 91002, 150, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 107901, 40001, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("ぺコリーヌ", 42, 6, 8, 0, 91002, 150, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 107501, 40001, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("コッコロ", 43, 7, 8, 0, 91002, 150, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 107601, 40001, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("キャル", 44, 8, 8, 0, 91002, 150, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 107801, 40001, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("スズメ", 45, 9, 8, 0, 91002, 150, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 107701, 40001, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("タマキ", 46, 10, 8, 0, 91002, 150, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 107901, 40001, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("", 57, 1, 8, 0, 91002, 150, "", 0, 40003, 0);
