INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("リリ", 321, 1, 2, 0, 24001, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 125801, 40011, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("クリア", 322, 2, 2, 0, 24001, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 126001, 40011, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("プレシア", 323, 3, 2, 0, 24001, 1, "んーと。\nこれ、あげる。\nはい", 126101, 40011, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("リリ", 324, 4, 2, 0, 24001, 1, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 125801, 40011, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("クリア", 325, 5, 2, 0, 24001, 1, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 126001, 40011, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("プレシア", 326, 6, 2, 0, 24001, 1, "お兄。\nきてくれて、うれしい", 126101, 40011, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES ("", 327, 1, 8, 532001, 91002, 100, "", 0, 80009, 0);
